// Extraer datos del body
const {
  nombre,
  apellidos,
  tipoActividad,
  materiaSeleccionada,
  gradoSeleccionado,
  salonSeleccionado,
  tema,
  preguntasMultiple,
  preguntasAbiertas,
  instrucciones
} = $input.item.json.body;

// Mapear tipos de actividad
const tipos = {
  'evaluacion': 'Evaluación',
  'taller': 'Taller',
  'quiz': 'Quiz'
};

const tipoTexto = tipos[tipoActividad] || tipoActividad;

// Fecha actual EN ZONA HORARIA DE COLOMBIA
const fecha = new Date().toLocaleDateString('es-CO', { 
  year: 'numeric', 
  month: 'long', 
  day: 'numeric',
  timeZone: 'America/Bogota'
});

// Construir objeto en orden específico
const datos = {
  fecha: fecha,
  nombre: nombre,
  apellidos: apellidos,
  tipoActividad: tipoTexto,
  materia: materiaSeleccionada,
  grado: gradoSeleccionado
};

// Agregar salón justo después del grado (si existe)
if (salonSeleccionado) {
  datos.salon = salonSeleccionado;
}

// Continuar con el resto
datos.tema = tema;

// Agregar instrucciones después del tema (si existen)
if (instrucciones) {
  datos.instrucciones = instrucciones;
}

// Agregar preguntas al final
datos.preguntasMultiple = preguntasMultiple;
datos.preguntasAbiertas = preguntasAbiertas;
datos.totalPreguntas = preguntasMultiple + preguntasAbiertas;

return { json: datos };

// ==============================
// PROCESAR PREGUNTAS (CON SOPORTE PARA IMÁGENES INCRUSTADAS)
// - Soporta AI Agent y Message a model
// - Las imágenes quedan DENTRO del contenido de cada pregunta
// - Flask procesará las imágenes al encontrarlas
// Recomendado: Run Once for All Items
// ==============================

const datos = ($items('Datos sin archivos')?.[0]?.json) ?? {};

// --------- Extraer texto de salida (robusto) ----------
let respuesta = '';

// Intentar obtener de "Reemplazar con URLs" primero (si hay imágenes)
try {
  const reemplazado = $items('Reemplazar con URLs')?.[0]?.json;
  if (reemplazado && reemplazado.output) {
    respuesta = reemplazado.output;
  }
} catch (e) {
  // No existe el nodo "Reemplazar con URLs", continuar
}

// Si no hay respuesta, obtener directamente de AI Agent (sin imágenes)
if (!respuesta) {
  const agentOutput = $items('AI Agent')?.[0]?.json;

  if (agentOutput) {
    if (typeof agentOutput.output === 'string') {
      respuesta = agentOutput.output;
    } else if (Array.isArray(agentOutput.output) && agentOutput.output.length > 0) {
      const m0 = agentOutput.output[0];
      if (typeof m0 === 'string') respuesta = m0;
      else if (m0 && typeof m0 === 'object') {
        if (m0.content?.[0]?.text) respuesta = m0.content[0].text;
        else if (m0.content?.[0]?.output_text) respuesta = m0.content[0].output_text;
        else if (m0.output_text) respuesta = m0.output_text;
        else if (m0.content?.[0]?.type === 'output_text' && m0.content?.[0]?.text) respuesta = m0.content[0].text;
      }
    } else if (typeof agentOutput.text === 'string') {
      respuesta = agentOutput.text;
    }
  }
}

if (!respuesta || typeof respuesta !== 'string') {
  throw new Error(
    "No se encontró texto de salida. Verifica que el nodo 'AI Agent1' esté conectado correctamente."
  );
}

// Normalizar saltos
respuesta = respuesta.replace(/\r\n/g, '\n');

// ------------------------------
// 1) Separar preguntas de selección múltiple
// ------------------------------
const preguntasMultiple = [];
const regexMultiple = /---PREGUNTA---([\s\S]*?)---FIN---/g;
let m;

while ((m = regexMultiple.exec(respuesta)) !== null) {
  const bloque = m[1].trim();

  const numMatch = bloque.match(/^(\d+)\./);
  const numero = numMatch ? numMatch[1] : null;

  const correctaMatch = bloque.match(/CORRECTA:\s*([A-D])/);
  const correcta = correctaMatch ? correctaMatch[1] : null;

  const contenidoLimpio = bloque
    .replace(/\n*CORRECTA:\s*[A-D]\s*$/m, '')
    .trim();

  // El contenido puede incluir marcadores ---IMAGEN--- dentro
  // Flask los procesará cuando encuentre cada pregunta
  preguntasMultiple.push({ numero, contenido: contenidoLimpio, correcta });
}

// ------------------------------
// 2) Separar preguntas abiertas
// ------------------------------
const preguntasAbiertas = [];
const regexAbiertas = /---ABIERTA---([\s\S]*?)---FIN---/g;

while ((m = regexAbiertas.exec(respuesta)) !== null) {
  const bloque = m[1].trim();

  const numMatch = bloque.match(/^(\d+)\./);
  const numero = numMatch ? numMatch[1] : null;

  preguntasAbiertas.push({ numero, contenido: bloque });
}

// ------------------------------
// 3) Hoja de respuestas (solo de preguntas reales)
// ------------------------------
const hojaRespuestas = preguntasMultiple
  .filter((p) => p.numero && p.correcta)
  .map((p) => ({ numero: p.numero, correcta: p.correcta }));

return {
  json: {
    datos,
    preguntasMultiple, // Ya NO tiene recursos separados, las imágenes están dentro
    preguntasAbiertas,
    hojaRespuestas,
    totalMultiple: preguntasMultiple.length,
    totalAbiertas: preguntasAbiertas.length,
  },
};

